solution_code:
#include <stdio.h>

unsigned char set_bit(unsigned char val, int pos) {
    return val | (1 << pos);
}

unsigned char clear_bit(unsigned char val, int pos) {
    return val & ~(1 << pos);
}

unsigned char toggle_bit(unsigned char val, int pos) {
    return val ^ (1 << pos);
}

int test_bit(unsigned char val, int pos) {
    return (val >> pos) & 1;
}

validation.test_code:
void test_set_bit(void) {
    TEST_ASSERT_EQUAL_INT(0xAD, set_bit(0xA5, 3));
    TEST_ASSERT_EQUAL_INT(0xA5, set_bit(0xA5, 5));
    TEST_ASSERT_EQUAL_INT(0xFF, set_bit(0xFE, 0));
    TEST_ASSERT_EQUAL_INT(0xFF, set_bit(0xFF, 7));
}

void test_clear_bit(void) {
    TEST_ASSERT_EQUAL_INT(0xA1, clear_bit(0xA5, 2));
    TEST_ASSERT_EQUAL_INT(0x85, clear_bit(0xA5, 5));
    TEST_ASSERT_EQUAL_INT(0x7E, clear_bit(0xFE, 7));
    TEST_ASSERT_EQUAL_INT(0xFE, clear_bit(0xFF, 0));
}

void test_toggle_bit(void) {
    TEST_ASSERT_EQUAL_INT(0xA4, toggle_bit(0xA5, 0));
    TEST_ASSERT_EQUAL_INT(0xA5, toggle_bit(0xA4, 0));
    TEST_ASSERT_EQUAL_INT(0x85, toggle_bit(0xA5, 5));
    TEST_ASSERT_EQUAL_INT(0x25, toggle_bit(0xA5, 7));
}

void test_test_bit(void) {
    TEST_ASSERT_EQUAL_INT(1, test_bit(0xA5, 0));
    TEST_ASSERT_EQUAL_INT(0, test_bit(0xA5, 1));
    TEST_ASSERT_EQUAL_INT(1, test_bit(0xA5, 5));
    TEST_ASSERT_EQUAL_INT(1, test_bit(0xA5, 7));
}

int main(void) {
    RUN_TEST(test_set_bit);
    RUN_TEST(test_clear_bit);
    RUN_TEST(test_toggle_bit);
    RUN_TEST(test_test_bit);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

